from typing import List

class Solution:
    def minimizeConcatenatedLength(self, words: List[str]) -> int:
        n = len(words)
        # dp[i][first][last] = min length of the string formed by the first i+1 words
        # with first character 'first' and last character 'last'
        dp = [{} for _ in range(n)]

        # Initialize the first word
        first_char = words[0][0]
        last_char = words[0][-1]
        dp[0][(first_char, last_char)] = len(words[0])

        for i in range(1, n):
            curr_word = words[i]
            curr_first = curr_word[0]
            curr_last = curr_word[-1]
            curr_len = len(curr_word)

            for (prev_first, prev_last), prev_total_len in dp[i-1].items():
                # Option 1: join previous string with current word
                if prev_last == curr_first:
                    new_total_len = prev_total_len + curr_len - 1
                else:
                    new_total_len = prev_total_len + curr_len
                key = (prev_first, curr_last)
                if key in dp[i]:
                    dp[i][key] = min(dp[i][key], new_total_len)
                else:
                    dp[i][key] = new_total_len

                # Option 2: join current word with previous string
                if curr_last == prev_first:
                    new_total_len = prev_total_len + curr_len - 1
                else:
                    new_total_len = prev_total_len + curr_len
                key = (curr_first, prev_last)
                if key in dp[i]:
                    dp[i][key] = min(dp[i][key], new_total_len)
                else:
                    dp[i][key] = new_total_len

        # Find the minimum length in the last dp state
        return min(dp[-1].values())
